/**
 * Webhook notification adapter — delivers notifications via HTTP POST to a URL.
 *
 * Features:
 * - Formats notification payload as JSON and POSTs to the recipient URL
 * - URL validation for recipient webhook endpoints
 * - Configurable default headers (e.g., Content-Type, Authorization)
 * - Optional HMAC-SHA256 payload signing via a shared secret
 * - Configurable timeout for webhook delivery
 * - Priority-aware metadata in the webhook payload
 *
 * Recipient Resolution:
 * The `recipient` field in the notification payload is treated as the webhook URL.
 * The adapter validates this URL before attempting delivery.
 *
 * Implements: NotificationAdapter (channel: 'webhook')
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the webhook adapter.
 */
export interface WebhookAdapterConfig {
  /** Default HTTP headers to include in every webhook request */
  defaultHeaders: Record<string, string>;
  /** Request timeout in milliseconds */
  timeout: number;
  /** Whether the adapter is enabled. When false, isAvailable() returns false. */
  enabled: boolean;
  /** Optional shared secret for HMAC-SHA256 payload signing */
  secret?: string;
}

/** Default webhook adapter configuration. */
export const defaultWebhookConfig: WebhookAdapterConfig = {
  defaultHeaders: {
    'Content-Type': 'application/json',
  },
  timeout: 5000,
  enabled: true,
};

/**
 * Represents a webhook delivery record.
 * Used internally by the adapter to structure outgoing webhook requests.
 */
export interface WebhookDelivery {
  /** Target webhook URL */
  url: string;
  /** HTTP method used */
  method: string;
  /** Request headers */
  headers: Record<string, string>;
  /** JSON payload that was sent */
  payload: WebhookPayload;
  /** Timestamp of the delivery attempt */
  timestamp: Date;
}

/**
 * The JSON payload structure sent to webhook endpoints.
 */
export interface WebhookPayload {
  /** Notification event type — always 'notification' */
  event: string;
  /** Notification subject / summary */
  subject: string;
  /** Notification body content */
  body: string;
  /** Notification priority level */
  priority: string;
  /** ISO-8601 timestamp of when the notification was sent */
  timestamp: string;
  /** Optional additional metadata from the notification */
  metadata?: Record<string, string>;
}

/** Basic URL validation pattern (http:// or https://). */
const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private config: WebhookAdapterConfig;
  private deliveries: WebhookDelivery[] = [];

  constructor(config?: Partial<WebhookAdapterConfig>) {
    this.config = {
      ...defaultWebhookConfig,
      defaultHeaders: {
        ...defaultWebhookConfig.defaultHeaders,
        ...config?.defaultHeaders,
      },
      timeout: config?.timeout ?? defaultWebhookConfig.timeout,
      enabled: config?.enabled ?? defaultWebhookConfig.enabled,
      secret: config?.secret,
    };
  }

  // ---------------------------------------------------------------------------
  // NotificationAdapter Interface
  // ---------------------------------------------------------------------------

  /**
   * Send a notification via webhook (HTTP POST).
   *
   * Processing pipeline:
   * 1. Check adapter availability.
   * 2. Validate the recipient URL.
   * 3. Format the notification as a JSON payload.
   * 4. Build request headers (defaults + signing if configured).
   * 5. Deliver (currently in-memory; replace with HTTP client for production).
   * 6. Return delivery result.
   *
   * @param payload - The notification to deliver via webhook.
   * @returns Result indicating delivery success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.isAvailable()) {
      return {
        success: false,
        errorMessage: 'Webhook adapter is not available (disabled in configuration)',
      };
    }

    try {
      // Step 1: Validate the recipient URL
      if (!this.validateUrl(payload.recipient)) {
        this.logger.warn(`Invalid webhook URL: ${payload.recipient}`);
        return {
          success: false,
          errorMessage: `Invalid webhook URL: ${payload.recipient}`,
        };
      }

      // Step 2: Format the JSON payload
      const webhookPayload = this.formatPayload(payload);

      // Step 3: Build request headers
      const headers = this.buildHeaders(webhookPayload);

      // Step 4: Create delivery record
      const delivery: WebhookDelivery = {
        url: payload.recipient,
        method: 'POST',
        headers,
        payload: webhookPayload,
        timestamp: new Date(),
      };

      // Step 5: Deliver (in-memory store; replace with HTTP client for production)
      this.logger.info(
        `Webhook delivered: url=${delivery.url}, subject="${webhookPayload.subject}"`,
      );
      this.deliveries.push(delivery);

      return {
        success: true,
        adapterResponse: {
          deliveryId: `webhook-${Date.now()}`,
          url: payload.recipient,
          method: 'POST',
        },
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown webhook delivery error';
      this.logger.error(`Webhook delivery failed: ${errorMessage}`);
      return {
        success: false,
        errorMessage,
      };
    }
  }

  /**
   * Check if the webhook adapter is available for sending.
   */
  isAvailable(): boolean {
    return this.config.enabled;
  }

  // ---------------------------------------------------------------------------
  // URL Validation
  // ---------------------------------------------------------------------------

  /**
   * Validate that a string is a well-formed HTTP/HTTPS URL.
   *
   * @param url - The string to validate.
   * @returns true if the string is a valid URL format.
   */
  validateUrl(url: string): boolean {
    return URL_REGEX.test(url);
  }

  // ---------------------------------------------------------------------------
  // Test Helpers
  // ---------------------------------------------------------------------------

  /**
   * Get all webhook deliveries made by this adapter (useful for testing).
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Clear the deliveries log (useful for testing).
   */
  clearDeliveries(): void {
    this.deliveries = [];
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<WebhookAdapterConfig> {
    return { ...this.config };
  }

  // ---------------------------------------------------------------------------
  // Private Methods
  // ---------------------------------------------------------------------------

  /**
   * Format a NotificationPayload into a WebhookPayload JSON structure.
   *
   * @param payload - The notification payload.
   * @returns The formatted webhook JSON payload.
   */
  private formatPayload(payload: NotificationPayload): WebhookPayload {
    const webhookPayload: WebhookPayload = {
      event: 'notification',
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      timestamp: new Date().toISOString(),
    };

    // Include metadata if present
    if (payload.metadata && Object.keys(payload.metadata).length > 0) {
      webhookPayload.metadata = { ...payload.metadata };
    }

    return webhookPayload;
  }

  /**
   * Build HTTP headers for the webhook request.
   * Starts with default headers and adds a signature header if a secret is configured.
   *
   * @param payload - The webhook payload (used for signature computation).
   * @returns The complete set of request headers.
   */
  private buildHeaders(payload: WebhookPayload): Record<string, string> {
    const headers: Record<string, string> = {
      ...this.config.defaultHeaders,
    };

    // Add signature header if a secret is configured
    if (this.config.secret) {
      headers['X-Webhook-Signature'] = this.computeSignature(payload);
    }

    return headers;
  }

  /**
   * Compute an HMAC-SHA256 signature for the webhook payload.
   * In production, this would use crypto.createHmac. For now, returns
   * a deterministic placeholder based on the secret and payload.
   *
   * @param payload - The webhook payload to sign.
   * @returns The computed signature string.
   */
  private computeSignature(payload: WebhookPayload): string {
    // In-memory/testing implementation: deterministic signature placeholder.
    // In production, replace with: crypto.createHmac('sha256', secret).update(JSON.stringify(payload)).digest('hex')
    const content = JSON.stringify(payload);
    return `sha256=${this.simpleHash(this.config.secret + ':' + content)}`;
  }

  /**
   * Simple deterministic hash for testing purposes.
   * NOT cryptographically secure — replace with real HMAC in production.
   */
  private simpleHash(input: string): string {
    let hash = 0;
    for (let i = 0; i < input.length; i++) {
      const char = input.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash).toString(16).padStart(8, '0');
  }
}

