import { describe, it, expect, beforeEach } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;

  beforeEach(() => {
    adapter = new WebhookAdapter();
  });

  describe('channel', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('isAvailable', () => {
    it('should be available by default', () => {
      expect(adapter.isAvailable()).toBe(true);
    });

    it('should be unavailable when disabled', () => {
      const disabled = new WebhookAdapter({ enabled: false });
      expect(disabled.isAvailable()).toBe(false);
    });
  });

  describe('send', () => {
    const payload: NotificationPayload = {
      recipient: 'https://hooks.example.com/webhook',
      subject: 'Test Subject',
      body: 'Test body content',
      channel: 'webhook',
      priority: 'normal',
    };

    it('should send a webhook successfully', async () => {
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.url).toBe('https://hooks.example.com/webhook');
      expect(result.adapterResponse?.method).toBe('POST');
    });

    it('should record deliveries', async () => {
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/webhook');
      expect(deliveries[0]?.method).toBe('POST');
      expect(deliveries[0]?.payload.subject).toBe('Test Subject');
      expect(deliveries[0]?.payload.body).toBe('Test body content');
    });

    it('should format payload as JSON with expected structure', async () => {
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      const webhookPayload = deliveries[0]?.payload;

      expect(webhookPayload?.event).toBe('notification');
      expect(webhookPayload?.subject).toBe('Test Subject');
      expect(webhookPayload?.body).toBe('Test body content');
      expect(webhookPayload?.priority).toBe('normal');
      expect(webhookPayload?.timestamp).toBeDefined();
    });

    it('should include timestamp as ISO-8601 string in payload', async () => {
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      const timestamp = deliveries[0]?.payload.timestamp;

      // Verify it's a valid ISO-8601 date
      expect(timestamp).toBeDefined();
      const parsed = new Date(timestamp!);
      expect(parsed.toISOString()).toBe(timestamp);
    });

    it('should fail when adapter is disabled', async () => {
      const disabled = new WebhookAdapter({ enabled: false });
      const result = await disabled.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('not available');
    });

    it('should include metadata in webhook payload when present', async () => {
      const payloadWithMeta: NotificationPayload = {
        ...payload,
        metadata: { orderId: 'ORD-001', source: 'order-service' },
      };

      await adapter.send(payloadWithMeta);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.metadata).toEqual({
        orderId: 'ORD-001',
        source: 'order-service',
      });
    });

    it('should not include metadata in payload when not present', async () => {
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.metadata).toBeUndefined();
    });

    it('should set Content-Type header to application/json by default', async () => {
      await adapter.send(payload);

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.headers['Content-Type']).toBe('application/json');
    });

    it('should include custom default headers in request', async () => {
      const custom = new WebhookAdapter({
        defaultHeaders: {
          'Authorization': 'Bearer test-token',
          'X-Custom': 'custom-value',
        },
      });

      await custom.send(payload);

      const deliveries = custom.getDeliveries();
      expect(deliveries[0]?.headers['Authorization']).toBe('Bearer test-token');
      expect(deliveries[0]?.headers['X-Custom']).toBe('custom-value');
      // Content-Type should also be present (from defaults)
      expect(deliveries[0]?.headers['Content-Type']).toBe('application/json');
    });
  });

  // =========================================================================
  // URL Validation Tests
  // =========================================================================

  describe('URL validation', () => {
    it('should accept valid HTTPS URLs', () => {
      expect(adapter.validateUrl('https://hooks.example.com/webhook')).toBe(true);
      expect(adapter.validateUrl('https://api.service.io/v1/notify')).toBe(true);
      expect(adapter.validateUrl('https://example.com:8080/path')).toBe(true);
    });

    it('should accept valid HTTP URLs', () => {
      expect(adapter.validateUrl('http://localhost:3000/webhook')).toBe(true);
      expect(adapter.validateUrl('http://internal.service/notify')).toBe(true);
    });

    it('should reject invalid URLs', () => {
      expect(adapter.validateUrl('')).toBe(false);
      expect(adapter.validateUrl('not-a-url')).toBe(false);
      expect(adapter.validateUrl('ftp://files.example.com')).toBe(false);
      expect(adapter.validateUrl('example.com/webhook')).toBe(false);
      expect(adapter.validateUrl('://missing-protocol.com')).toBe(false);
    });

    it('should fail send for invalid webhook URL', async () => {
      const payload: NotificationPayload = {
        recipient: 'not-a-valid-url',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid webhook URL');
    });

    it('should fail send for empty URL', async () => {
      const payload: NotificationPayload = {
        recipient: '',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid webhook URL');
    });
  });

  // =========================================================================
  // Payload Signing Tests
  // =========================================================================

  describe('payload signing', () => {
    it('should include X-Webhook-Signature header when secret is configured', async () => {
      const signed = new WebhookAdapter({ secret: 'my-secret-key' });

      await signed.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Signed Notification',
        body: 'This is signed',
        channel: 'webhook',
        priority: 'normal',
      });

      const deliveries = signed.getDeliveries();
      expect(deliveries[0]?.headers['X-Webhook-Signature']).toBeDefined();
      expect(deliveries[0]?.headers['X-Webhook-Signature']).toMatch(/^sha256=/);
    });

    it('should not include signature header when no secret is configured', async () => {
      await adapter.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Unsigned Notification',
        body: 'This is unsigned',
        channel: 'webhook',
        priority: 'normal',
      });

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.headers['X-Webhook-Signature']).toBeUndefined();
    });

    it('should produce different signatures for different payloads', async () => {
      const signed = new WebhookAdapter({ secret: 'my-secret-key' });

      await signed.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'First',
        body: 'First body',
        channel: 'webhook',
        priority: 'normal',
      });

      await signed.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Second',
        body: 'Second body',
        channel: 'webhook',
        priority: 'high',
      });

      const deliveries = signed.getDeliveries();
      const sig1 = deliveries[0]?.headers['X-Webhook-Signature'];
      const sig2 = deliveries[1]?.headers['X-Webhook-Signature'];

      expect(sig1).toBeDefined();
      expect(sig2).toBeDefined();
      expect(sig1).not.toBe(sig2);
    });
  });

  // =========================================================================
  // Priority Tests
  // =========================================================================

  describe('priority handling', () => {
    it('should include priority in the webhook payload', async () => {
      await adapter.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'high',
      });

      const deliveries = adapter.getDeliveries();
      expect(deliveries[0]?.payload.priority).toBe('high');
    });

    it('should correctly pass each priority level', async () => {
      const priorities = ['low', 'normal', 'high', 'urgent'] as const;

      for (const priority of priorities) {
        adapter.clearDeliveries();
        await adapter.send({
          recipient: 'https://hooks.example.com/webhook',
          subject: 'Test',
          body: 'Body',
          channel: 'webhook',
          priority,
        });

        const deliveries = adapter.getDeliveries();
        expect(deliveries[0]?.payload.priority).toBe(priority);
      }
    });
  });

  // =========================================================================
  // Management / Test Helpers Tests
  // =========================================================================

  describe('management', () => {
    it('should clear deliveries', async () => {
      await adapter.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'normal',
      });

      adapter.clearDeliveries();
      expect(adapter.getDeliveries()).toHaveLength(0);
    });

    it('should return config', () => {
      const config = adapter.getConfig();
      expect(config.enabled).toBe(true);
      expect(config.timeout).toBe(5000);
      expect(config.defaultHeaders['Content-Type']).toBe('application/json');
    });

    it('should return config with custom values', () => {
      const custom = new WebhookAdapter({
        timeout: 10000,
        secret: 'test-secret',
      });

      const config = custom.getConfig();
      expect(config.timeout).toBe(10000);
      expect(config.secret).toBe('test-secret');
    });
  });

  // =========================================================================
  // Integration: Multiple sends, different configs
  // =========================================================================

  describe('integration', () => {
    it('should handle multiple sends independently', async () => {
      const payload1: NotificationPayload = {
        recipient: 'https://hooks.example.com/webhook1',
        subject: 'First',
        body: 'First body',
        channel: 'webhook',
        priority: 'normal',
      };

      const payload2: NotificationPayload = {
        recipient: 'https://hooks.example.com/webhook2',
        subject: 'Second',
        body: 'Second body',
        channel: 'webhook',
        priority: 'high',
      };

      await adapter.send(payload1);
      await adapter.send(payload2);

      const deliveries = adapter.getDeliveries();
      expect(deliveries).toHaveLength(2);
      expect(deliveries[0]?.url).toBe('https://hooks.example.com/webhook1');
      expect(deliveries[0]?.payload.subject).toBe('First');
      expect(deliveries[1]?.url).toBe('https://hooks.example.com/webhook2');
      expect(deliveries[1]?.payload.subject).toBe('Second');
    });

    it('should work with custom headers and signing combined', async () => {
      const customAdapter = new WebhookAdapter({
        defaultHeaders: {
          'Authorization': 'Bearer webhook-token',
        },
        secret: 'signing-secret',
      });

      const payload: NotificationPayload = {
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Full Integration',
        body: 'Testing all features together',
        channel: 'webhook',
        priority: 'urgent',
        metadata: { orderId: 'ORD-999', eventType: 'order_created' },
      };

      const result = await customAdapter.send(payload);

      expect(result.success).toBe(true);

      const deliveries = customAdapter.getDeliveries();
      expect(deliveries).toHaveLength(1);

      const delivery = deliveries[0]!;
      // URL is correct
      expect(delivery.url).toBe('https://hooks.example.com/webhook');
      // Method is POST
      expect(delivery.method).toBe('POST');
      // Default Content-Type preserved
      expect(delivery.headers['Content-Type']).toBe('application/json');
      // Custom header included
      expect(delivery.headers['Authorization']).toBe('Bearer webhook-token');
      // Signature included
      expect(delivery.headers['X-Webhook-Signature']).toMatch(/^sha256=/);
      // Payload structured correctly
      expect(delivery.payload.event).toBe('notification');
      expect(delivery.payload.subject).toBe('Full Integration');
      expect(delivery.payload.body).toBe('Testing all features together');
      expect(delivery.payload.priority).toBe('urgent');
      expect(delivery.payload.metadata?.orderId).toBe('ORD-999');
      expect(delivery.payload.metadata?.eventType).toBe('order_created');
    });

    it('should record delivery timestamp', async () => {
      const before = new Date();

      await adapter.send({
        recipient: 'https://hooks.example.com/webhook',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'normal',
      });

      const after = new Date();
      const deliveries = adapter.getDeliveries();
      const deliveryTime = deliveries[0]?.timestamp;

      expect(deliveryTime).toBeDefined();
      expect(deliveryTime!.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(deliveryTime!.getTime()).toBeLessThanOrEqual(after.getTime());
    });
  });

  // =========================================================================
  // Registration with NotificationService (structural check)
  // =========================================================================

  describe('adapter interface compliance', () => {
    it('should implement all required NotificationAdapter methods', () => {
      expect(typeof adapter.channel).toBe('string');
      expect(typeof adapter.send).toBe('function');
      expect(typeof adapter.isAvailable).toBe('function');
    });

    it('should never throw from send — always returns NotificationResult', async () => {
      // Even with a bad URL, should return a result, not throw
      const result = await adapter.send({
        recipient: '',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
        priority: 'normal',
      });

      expect(result).toBeDefined();
      expect(typeof result.success).toBe('boolean');
    });
  });
});

